import React, { useEffect, useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { Jovem } from '../types';

const JovemDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [jovem, setJovem] = useState<Jovem | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchJovemDetails = async () => {
      try {
        setLoading(true);
        const response = await fetch(`/api/jovens/${id}`, {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('token')}`
          }
        });

        if (!response.ok) {
          throw new Error('Erro ao carregar detalhes do jovem');
        }

        const data = await response.json();
        setJovem(data);
        setLoading(false);
      } catch (error) {
        console.error('Erro:', error);
        setError('Erro ao carregar dados. Por favor, tente novamente.');
        setLoading(false);
      }
    };

    if (id) {
      fetchJovemDetails();
    }
  }, [id]);

  const getBasePath = () => {
    if (user?.papel === 'instituicao_ensino') {
      return '/instituicao-ensino';
    } else if (user?.papel === 'chefe_empresa') {
      return '/chefe-empresa';
    } else if (user?.papel === 'instituicao_contratante') {
      return '/instituicao-contratante';
    }
    return '';
  };

  const handleVoltar = () => {
    navigate(`${getBasePath()}/jovens`);
  };

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="text-center py-12">
          <div className="inline-block h-8 w-8 animate-spin rounded-full border-4 border-solid border-current border-e-transparent align-[-0.125em] text-cursor-primary motion-reduce:animate-[spin_1.5s_linear_infinite]"></div>
          <p className="mt-4 text-cursor-text-secondary">Carregando informações...</p>
        </div>
      </div>
    );
  }

  if (error || !jovem) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="text-center py-12">
          <div className="bg-red-100 border border-red-200 text-red-700 px-4 py-3 rounded relative">
            <p>{error || 'Jovem não encontrado'}</p>
            <button
              onClick={handleVoltar}
              className="mt-4 inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-cursor-primary hover:bg-cursor-primary-dark focus:outline-none"
            >
              Voltar para lista
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="mb-6 flex items-center">
        <button
          onClick={handleVoltar}
          className="mr-4 inline-flex items-center text-cursor-text-secondary hover:text-cursor-primary"
        >
          <svg className="w-5 h-5 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
          </svg>
          Voltar
        </button>
        <h1 className="text-2xl font-bold text-cursor-text-primary">{jovem.nome}</h1>
      </div>

      <div className="bg-white rounded-lg shadow overflow-hidden">
        {/* Cabeçalho */}
        <div className="p-6 border-b border-gray-200">
          <div className="flex flex-col md:flex-row md:items-center md:justify-between">
            <div>
              <h2 className="text-xl font-semibold text-cursor-text-primary">{jovem.nome}</h2>
              <p className="text-cursor-text-secondary">{jovem.email}</p>
            </div>
            <div className="mt-4 md:mt-0 flex space-x-3">
              <button
                className="inline-flex items-center px-4 py-2 border border-cursor-primary text-sm font-medium rounded-md text-cursor-primary bg-white hover:bg-cursor-primary/10 focus:outline-none"
              >
                <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                </svg>
                Editar
              </button>
              <Link
                to={`${getBasePath()}/jovens/${jovem.id}/recomendar`}
                className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-cursor-primary hover:bg-cursor-primary-dark focus:outline-none"
              >
                <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z" />
                </svg>
                Recomendar
              </Link>
            </div>
          </div>
        </div>

        {/* Corpo do cartão */}
        <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Coluna da esquerda: Informações básicas */}
          <div>
            <h3 className="text-lg font-medium text-cursor-text-primary mb-4">Informações Básicas</h3>
            <div className="space-y-4">
              <div>
                <div className="text-sm font-medium text-cursor-text-tertiary">Idade</div>
                <div className="mt-1 text-cursor-text-primary">{jovem.idade} anos</div>
              </div>
              <div>
                <div className="text-sm font-medium text-cursor-text-tertiary">Formação</div>
                <div className="mt-1 text-cursor-text-primary">{jovem.formacao || 'Não informado'}</div>
              </div>
              <div>
                <div className="text-sm font-medium text-cursor-text-tertiary">Habilidades</div>
                <div className="mt-1">
                  {jovem.habilidades && jovem.habilidades.length > 0 ? (
                    <div className="flex flex-wrap gap-2">
                      {jovem.habilidades.map((habilidade, index) => (
                        <span key={index} className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-cursor-primary/10 text-cursor-primary">
                          {habilidade}
                        </span>
                      ))}
                    </div>
                  ) : (
                    <div className="text-cursor-text-secondary">Nenhuma habilidade informada</div>
                  )}
                </div>
              </div>
              <div>
                <div className="text-sm font-medium text-cursor-text-tertiary">Interesses</div>
                <div className="mt-1">
                  {jovem.interesses && jovem.interesses.length > 0 ? (
                    <div className="flex flex-wrap gap-2">
                      {jovem.interesses.map((interesse, index) => (
                        <span key={index} className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-cursor-accent/10 text-cursor-accent">
                          {interesse}
                        </span>
                      ))}
                    </div>
                  ) : (
                    <div className="text-cursor-text-secondary">Nenhum interesse informado</div>
                  )}
                </div>
              </div>
            </div>
          </div>

          {/* Coluna da direita: Planos futuros e vínculos */}
          <div>
            <h3 className="text-lg font-medium text-cursor-text-primary mb-4">Planos e Vínculos</h3>
            <div className="space-y-4">
              <div>
                <div className="text-sm font-medium text-cursor-text-tertiary">Planos Futuros</div>
                <div className="mt-1 text-cursor-text-primary">{jovem.planos_futuros || 'Não informado'}</div>
              </div>
              <div>
                <div className="text-sm font-medium text-cursor-text-tertiary">Instituições de Ensino</div>
                <div className="mt-1">
                  {jovem.instituicoes && jovem.instituicoes.length > 0 ? (
                    <ul className="space-y-2">
                      {jovem.instituicoes.map((instituicao, index) => (
                        <li key={index} className="p-3 bg-gray-50 rounded-lg">
                          <div className="flex justify-between">
                            <div className="text-sm font-medium text-cursor-text-primary">Instituição #{instituicao.instituicao_id}</div>
                            <span className={`px-2 py-0.5 text-xs rounded-full ${
                              instituicao.status === 'Matriculado' ? 'bg-green-100 text-green-800' : 
                              instituicao.status === 'Egresso' ? 'bg-gray-100 text-gray-800' : 
                              'bg-blue-100 text-blue-800'
                            }`}>
                              {instituicao.status}
                            </span>
                          </div>
                          <div className="text-sm text-cursor-text-secondary mt-1">Curso: {instituicao.curso}</div>
                        </li>
                      ))}
                    </ul>
                  ) : (
                    <div className="text-cursor-text-secondary">Nenhuma instituição vinculada</div>
                  )}
                </div>
              </div>
              <div>
                <div className="text-sm font-medium text-cursor-text-tertiary">Empresas</div>
                <div className="mt-1">
                  {jovem.empresas && jovem.empresas.length > 0 ? (
                    <ul className="space-y-2">
                      {jovem.empresas.map((empresa, index) => (
                        <li key={index} className="p-3 bg-gray-50 rounded-lg">
                          <div className="flex justify-between">
                            <div className="text-sm font-medium text-cursor-text-primary">Empresa #{empresa.empresa_id}</div>
                            <span className={`px-2 py-0.5 text-xs rounded-full ${
                              empresa.status === 'Contratado' ? 'bg-green-100 text-green-800' : 
                              empresa.status === 'Estagiário' ? 'bg-blue-100 text-blue-800' : 
                              'bg-gray-100 text-gray-800'
                            }`}>
                              {empresa.status}
                            </span>
                          </div>
                          <div className="text-sm text-cursor-text-secondary mt-1">Cargo: {empresa.cargo}</div>
                        </li>
                      ))}
                    </ul>
                  ) : (
                    <div className="text-cursor-text-secondary">Nenhuma empresa vinculada</div>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default JovemDetails;
